CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_atm_lon_card() RETURNS trigger AS $BODY$
declare
  li_count_membank integer;
  ls_memno sc_lon_m_contract.membership_no%type;
BEGIN
  BEGIN
--return ;
  if coalesce(NEW.seq_no::text, '') = '' or NEW.seq_no = 0 then
    select max(seq_no) into STRICT NEW.seq_no
    from sc_atm_lon_card
    where loan_contract_no = NEW.loan_contract_no;
    NEW.seq_no := coalesce(NEW.seq_no,0) + 1;
  end if;
  if coalesce(trim(both NEW.NEW_SEND_STATUS)::text, '') = '' then NEW.NEW_SEND_STATUS := '0';end if;
  if coalesce(NEW.balance_send::text, '') = '' then NEW.balance_send := 0;end if;
  if coalesce(trim(both NEW.modify_status)::text, '') = '' then NEW.modify_status := 'W';end if;
  if coalesce(NEW.send_last_no::text, '') = '' then NEW.send_last_no := 0;end if;
  if coalesce(trim(both NEW.CLOSE_STATUS)::text, '') = '' then NEW.CLOSE_STATUS := '0';end if;
  if coalesce(NEW.PRESS_AMOUNT_REAL::text, '') = '' then NEW.PRESS_AMOUNT_REAL := 0;end if;

  if coalesce(NEW.date_regis::text, '') = '' then
    BEGIN
      select BEGINing_of_contract into STRICT NEW.date_regis
      from sc_lon_m_contract
      where loan_contract_no = NEW.loan_contract_no;
    exception
      when no_data_found then null;
      when others then CALL spa_dberror('select failed!');
    end;
  end if;

  if NEW.close_status = 'C' then
    NEW.close_status := '1';
  end if;

  --ให้เป็นได้แค่ 2 ค่า 
  if NEW.close_status <> '0' and NEW.close_status <> '1' then
    NEW.close_status := '1';
    CALL spa_dberror('T33:TBIR_SC_ATM_LON_CARD valid  close_status=' || NEW.close_status);
  end if;

  --Niorn 2023-07-10 JUN ปรับขนาด bank_code
  if trim(both NEW.bank_code) = '06'  then NEW.bank_code := '006';end if;
  if trim(both NEW.bank_code) = '25' then NEW.bank_code := '025';end if;

--Niorn 2024-03-11 TGE Edit Mapping
  --if   :old.close_status = '1' and :new.close_status = '0' then
  if   OLD.close_status <> NEW.close_status  then
    update sc_lon_m_loan_card
    set close_status = NEW.close_status
    where loan_contract_no = NEW.loan_contract_no
    --and close_status = '1' 
;
  end if;

  --Niorn 2024-08-22 TGE
  --แก้ไข Status and Bank Acc no
--  if  ( :old.NEW_SEND_STATUS  is not null and :new.NEW_SEND_STATUS <> :old.NEW_SEND_STATUS )
--    or ( :old.MODIFY_STATUS  is not null and :new.MODIFY_STATUS <> :old.MODIFY_STATUS )
--    or ( :old.CLOSE_STATUS  is not null and :new.CLOSE_STATUS <> :old.CLOSE_STATUS )    
--    or ( :old.CURRENT_ACCOUNT  is not null and :new.CURRENT_ACCOUNT <> :old.CURRENT_ACCOUNT )  
--  then 
--   --insert  SC_LON_EDIT_ATM
--   INSERT INTO SC_LON_EDIT_ATM
--           ( LOAN_CONTRACT_NO,          ENTRY_DATE,                 ENTRY_ID,   
--           ENTRY_BR,                    OPERATE_DATE,    
--           PRE_NEW_SEND_STATUS,         PRE_MODIFY_STATUS,          PRE_CLOSE_STATUS,          
--           PRE_CURRENT_ACCOUNT,
--
--           NEW_SEND_STATUS,             MODIFY_STATUS,               CLOSE_STATUS,
--           CURRENT_ACCOUNT
--           )  
--  VALUES ( :new.LOAN_CONTRACT_NO,       sysdate,                   current_setting('app.login_id', true),   
--           current_setting('app.login_br', true),      TO_DATE( sysdate ),            
--           :old.NEW_SEND_STATUS,         :old.MODIFY_STATUS,     :old.CLOSE_STATUS,  
--           :old.CURRENT_ACCOUNT,
--
--           :new.NEW_SEND_STATUS,       :new.MODIFY_STATUS,         :new.CLOSE_STATUS,
--           :new.CURRENT_ACCOUNT
--           ) 
--           ;
--  end if;
NEW.entry_id := current_setting('app.login_id', true);
NEW.entry_date := statement_timestamp();

  END;
RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
